public class ServiceA {
    private final ServiceB serviceB;
    public ServiceA(@Lazy ServiceB serviceB) {
        this.serviceB = serviceB; // Proxy created, actual bean deferred
    }
}

// Observe context initialization lifecycle
@Component
public class ContextLifecycleObserver
        implements BeanFactoryPostProcessor,
        BeanPostProcessor,
        ApplicationContextAware,
        ApplicationRunner {

    private static final Logger log =
        LoggerFactory.getLogger(ContextLifecycleObserver.class);

    @Override
    public void postProcessBeanFactory(
            ConfigurableListableBeanFactory bf) {
        log.info("[1] BeanFactoryPostProcessor: bean definitions created");
    }

    @Override
    public Object postProcessBeforeInitialization(
            Object bean, String name) {
        log.info("[3] BeanPostProcessor.before: {}", name);
        return bean;
    }

    @Override
    public Object postProcessAfterInitialization(
            Object bean, String name) {
        log.info("[4] BeanPostProcessor.after: {}", name);
        return bean;
    }

    @Override
    public void setApplicationContext(
            ApplicationContext ctx) {
        log.info("[5] ApplicationContextAware: context set");
    }

    @Override
    public void run(ApplicationArguments args) {
        log.info("[6] ApplicationRunner: app ready for requests");
    }
}

