// Basic @Transactional
@Service
public class PaymentService {
    @Autowired private PaymentRepository repo;
    @Autowired private AccountRepository accountRepo;

    @Transactional
    public void transferMoney(long from, long to, BigDecimal amount) {
        // All queries in this method are in one transaction
        Account fromAccount = accountRepo.findById(from).orElseThrow();
        Account toAccount = accountRepo.findById(to).orElseThrow();

        fromAccount.debit(amount);
        toAccount.credit(amount);

        accountRepo.save(fromAccount);
        accountRepo.save(toAccount);
        // Commits here if no exception
    }
}

