// persist() — insert only
@Service
public class PersistExample {
    @Autowired private EntityManager em;

    @Transactional
    public void demo() {
        // Transient entity (not in DB, no ID)
        User user = new User(null, "John", "john@example.com");
        em.persist(user); // Marked for INSERT
        // At transaction end, SQL INSERT executes
        // Now user has generated ID from DB

        user.setEmail("newemail@example.com");
        // Change is tracked, UPDATE executes at flush/commit

        User detached = new User(1L, "Jane", "jane@example.com");
        em.persist(detached); // Throws EntityExistsException!
        // ID already exists, can't persist
    }
}

// merge() — reattach detached entity
@Service
public class MergeExample {
    @Autowired private EntityManager em;

    @Transactional
    public void demo(User detachedUser) {
        // detachedUser came from a previous session
        // Modifications to it are not tracked
        detachedUser.setEmail("updated@example.com");
        // This change is NOT tracked in current transaction

        User managed = em.merge(detachedUser);
        // managed is the tracked copy in current context
        // Changes to managed ARE tracked
        managed.setPhone("555-1234");
        // At transaction end, UPDATE executes with all changes
    }
}

// save() from Spring Data — handles both cases
@Service
public class SaveExample {
    @Autowired private UserRepository repo; // extends CrudRepository

    @Transactional
    public void demo() {
        // New entity
        User newUser = new User(null, "John", "john@example.com");
        User saved = repo.save(newUser);
        // Calls persist() internally — INSERT

        // Existing entity
        User existing = repo.findById(1L).orElseThrow();
        existing.setEmail("newemail@example.com");
        repo.save(existing);
        // Calls merge() internally — UPDATE
    }
}

// Lazy loading (default) — causes N+1 problem
@Entity
public class User {
    @Id private Long id;
    private String name;

    @OneToMany(mappedBy = "user")
    private List<Order> orders; // Lazy loaded
}

@Service
public class UserService {
    @Autowired private UserRepository repo;

    @Transactional
    public List<UserDTO> getAllUsersWithOrders() {
        List<User> users = repo.findAll(); // 1 query
        return users.stream().map(u -> {
            int orderCount = u.getOrders().size(); // N queries!
            // Each call to getOrders() triggers a query
            return new UserDTO(u.getId(), u.getName(), orderCount);
        }).collect(toList());
    }
    // Result: 1001 queries for 1000 users
}

