// Idempotent payment API
@Entity
public class IdempotencyRecord {
    @Id private String idempotencyKey;
    private String result;  // JSON result
    private LocalDateTime createdAt;
    private LocalDateTime expiresAt;
}

@Repository
public interface IdempotencyRepository
        extends JpaRepository<IdempotencyRecord, String> {}

@RestController
@RequestMapping("/api/payments")
public class PaymentController {
    @Autowired private PaymentService paymentService;
    @Autowired private IdempotencyRepository idempotencyRepo;

    @PostMapping
    public ResponseEntity<PaymentResponse> processPayment(
            @RequestBody PaymentRequest request,
            @RequestHeader("Idempotency-Key") String idempotencyKey) {

        // Check if this key was already processed
        Optional<IdempotencyRecord> existing =
            idempotencyRepo.findById(idempotencyKey);

        if (existing.isPresent()) {
            // Return cached result — exactly once
            String cachedResult = existing.get().getResult();
            return ResponseEntity.ok(
                objectMapper.readValue(
                    cachedResult, PaymentResponse.class));
        }

        // Process the payment
        PaymentResponse response = paymentService.charge(
            request.getAmount(),
            request.getAccountId(),
            request.getDescription());

        // Store result with idempotency key
        IdempotencyRecord record = new IdempotencyRecord();
        record.setIdempotencyKey(idempotencyKey);
        record.setResult(objectMapper.writeValueAsString(response));
        record.setCreatedAt(LocalDateTime.now());
        record.setExpiresAt(
            LocalDateTime.now().plusHours(24));
        idempotencyRepo.save(record);

        return ResponseEntity.status(201).body(response);
    }
}

