// Saga pattern — orchestration
@Service
public class OrderSagaOrchestrator {
    @Autowired private PaymentServiceClient payment;
    @Autowired private OrderRepository orders;
    @Autowired private InventoryServiceClient inventory;

    @Transactional
    public Order createOrder(CreateOrderRequest request) {
        Order order = new Order(request);
        order.setStatus("PENDING");
        orders.save(order);

        try {
            // Step 1: Charge payment
            PaymentResult paymentResult =
                payment.charge(order.getId(), request.getAmount());
            if (!paymentResult.isSuccess()) {
                throw new PaymentFailedException();
            }

            // Step 2: Reserve inventory
            InventoryResult inventoryResult =
                inventory.reserve(order.getId(),
                    request.getItems());
            if (!inventoryResult.isSuccess()) {
                // Compensate: refund payment
                payment.refund(paymentResult.getTransactionId());
                throw new InventoryUnavailableException();
            }

            order.setStatus("CONFIRMED");
            orders.save(order);
            return order;

        } catch (Exception ex) {
            order.setStatus("FAILED");
            orders.save(order);
            throw ex;
        }
    }
}

