// Event sourcing — immutable events
@Data
public abstract class DomainEvent {
    protected UUID aggregateId;
    protected LocalDateTime timestamp;
    protected int version;
}

@Data
public class MoneyDepositedEvent extends DomainEvent {
    private BigDecimal amount;
    private String reason;
}

@Data
public class MoneyWithdrawnEvent extends DomainEvent {
    private BigDecimal amount;
    private String reason;
}

// Aggregate that rebuilds state from events
@Data
public class Account {
    private UUID id;
    private BigDecimal balance;
    private List<DomainEvent> uncommittedEvents;

    public Account(UUID id) {
        this.id = id;
        this.balance = BigDecimal.ZERO;
        this.uncommittedEvents = new ArrayList<>();
    }

    public void deposit(BigDecimal amount, String reason) {
        MoneyDepositedEvent event = new MoneyDepositedEvent();
        event.setAggregateId(id);
        event.setAmount(amount);
        event.setReason(reason);
        event.setTimestamp(LocalDateTime.now());

        applyEvent(event);  // Update state
        uncommittedEvents.add(event);  // Record for persistence
    }

    public void withdraw(BigDecimal amount, String reason) {
        if (amount.compareTo(balance) > 0) {
            throw new InsufficientBalanceException();
        }
        MoneyWithdrawnEvent event = new MoneyWithdrawnEvent();
        event.setAggregateId(id);
        event.setAmount(amount);
        event.setReason(reason);
        event.setTimestamp(LocalDateTime.now());

        applyEvent(event);
        uncommittedEvents.add(event);
    }

    // State change logic
    private void applyEvent(DomainEvent event) {
        if (event instanceof MoneyDepositedEvent) {
            MoneyDepositedEvent e = (MoneyDepositedEvent) event;
            balance = balance.add(e.getAmount());
        } else if (event instanceof MoneyWithdrawnEvent) {
            MoneyWithdrawnEvent e = (MoneyWithdrawnEvent) event;
            balance = balance.subtract(e.getAmount());
        }
    }

    // Rebuild state from all past events
    public void loadFromEvents(List<DomainEvent> events) {
        for (DomainEvent event : events) {
            applyEvent(event);
        }
    }
}

// Event store (repository)
@Repository
public interface EventStore extends JpaRepository<StoredEvent, UUID> {
    List<StoredEvent> findByAggregateId(UUID aggregateId);
}

@Service
public class AccountService {
    @Autowired private EventStore eventStore;

    public Account getAccount(UUID accountId) {
        Account account = new Account(accountId);
        List<StoredEvent> events = eventStore.findByAggregateId(
            accountId);
        // Rebuild state by replaying events
        account.loadFromEvents(
            events.stream()
                .map(StoredEvent::getEvent)
                .collect(toList()));
        return account;
    }

    @Transactional
    public void saveAccount(Account account) {
        // Persist all new events
        for (DomainEvent event : account.getUncommittedEvents()) {
            StoredEvent stored = new StoredEvent();
            stored.setAggregateId(account.getId());
            stored.setEvent(event);
            stored.setTimestamp(event.getTimestamp());
            eventStore.save(stored);
        }
        account.getUncommittedEvents().clear();
    }
}

