// Audit logging with AOP
@Entity
@Table(name = "audit_log", indexes = {
    @Index(name = "idx_timestamp", columnList = "createdAt"),
    @Index(name = "idx_user", columnList = "userId"),
    @Index(name = "idx_action", columnList = "action")
})
public class AuditLog {
    @Id @GeneratedValue(strategy = GenerationType.AUTO)
    private UUID id;

    private UUID userId;
    private String action;
    @Lob private String resourceDetails;  // JSON
    private String result;  // SUCCESS, FAILURE
    @Lob private String errorMessage;
    private LocalDateTime createdAt;
    private String ipAddress;
    private String traceId;  // Correlation ID
}

@Target(ElementType.METHOD)
@Retention(RetentionPolicy.RUNTIME)
public @interface Auditable {
    String action();
}

@Component
@Aspect
public class AuditLoggingAspect {
    @Autowired private AuditRepository auditRepo;
    @Autowired private HttpServletRequest request;

    @Around("@annotation(auditable)")
    public Object audit(ProceedingJoinPoint jp,
                        Auditable auditable) throws Throwable {
        Object result = null;
        Exception exception = null;

        try {
            result = jp.proceed();
            return result;
        } catch (Exception ex) {
            exception = ex;
            throw ex;
        } finally {
            // Async log to avoid blocking
            auditLog(jp, auditable.action(), result,
                exception);
        }
    }

    private void auditLog(ProceedingJoinPoint jp,
                          String action,
                          Object result,
                          Exception ex) {
        // Queue async to not block the request
        CompletableFuture.runAsync(() -> {
            AuditLog log = new AuditLog();
            log.setId(UUID.randomUUID());
            log.setUserId(getCurrentUserId());
            log.setAction(action);
            log.setResourceDetails(
                objectMapper.writeValueAsString(
                    jp.getArgs()));
            log.setResult(ex == null ? "SUCCESS"
                : "FAILURE");
            if (ex != null) {
                log.setErrorMessage(ex.getMessage());
            }
            log.setCreatedAt(LocalDateTime.now());
            log.setIpAddress(request.getRemoteAddr());
            log.setTraceId(
                TraceContext.getCurrentTraceId());

            auditRepo.save(log);
        });
    }
}

