// Implement rate limiting in filter
@Component
public class RateLimitingFilter extends OncePerRequestFilter {
    @Autowired private RedisTemplate<String, String> redis;

    private static final String RATE_LIMIT_KEY = "rate_limit:";
    private static final int LIMIT_PER_MINUTE = 60;

    @Override
    protected void doFilterInternal(
            HttpServletRequest req,
            HttpServletResponse res,
            FilterChain chain) throws ServletException, IOException {

        String clientId = getClientId(req); // IP or user ID
        String key = RATE_LIMIT_KEY + clientId;

        Long count = redis.opsForValue().increment(key);
        if (count == 1) {
            // First request, set expiry
            redis.expire(key, Duration.ofMinutes(1));
        }

        res.setHeader("X-RateLimit-Limit",
            String.valueOf(LIMIT_PER_MINUTE));
        res.setHeader("X-RateLimit-Remaining",
            String.valueOf(Math.max(0,
                LIMIT_PER_MINUTE - count)));

        if (count > LIMIT_PER_MINUTE) {
            res.setStatus(429);
            res.setHeader("Retry-After",
                String.valueOf(redis.getExpire(key,
                    TimeUnit.SECONDS)));
            res.getWriter().write(
                "{\"error\":\"Rate limit exceeded\"}");
            return;
        }

        chain.doFilter(req, res);
    }

    private String getClientId(HttpServletRequest req) {
        // Try to get user ID from auth
        Object principal = SecurityContextHolder
            .getContext().getAuthentication()
            .getPrincipal();
        if (principal instanceof UserDetails) {
            return ((UserDetails) principal).getUsername();
        }
        // Fall back to IP
        return req.getRemoteAddr();
    }
}

// Spring Cloud Gateway rate limiter
@Configuration
public class GatewayConfig {
    @Bean
    public RouteLocator routes(RouteLocatorBuilder builder,
                               RedisRateLimiter limiter) {
        return builder.routes()
            .route("payment", r -> r
                .path("/api/payments/**")
                .filters(f -> f
                    .requestRateLimiter(
                        config -> config
                            .setRateLimiter(limiter)
                            .setKeyResolver(
                                exchange -> Mono.just(
                                    getClientId(exchange))))
                    .retry(3))
                .uri("http://payment-service"))
            .build();
    }
}

// Lua script for atomic rate limiting in Redis
private static final String RATE_LIMIT_SCRIPT =
    "local count = redis.call('INCR', KEYS[1])\n" +
    "if count == 1 then\n" +
    "  redis.call('EXPIRE', KEYS[1], ARGV[1])\n" +
    "end\n" +
    "return count";

public boolean isAllowed(String clientId, int limit) {
    Long count = redis.execute(
        RedisScript.of(RATE_LIMIT_SCRIPT, Long.class),
        List.of("rate_limit:" + clientId),
        String.valueOf(60)); // 60 second window
    return count <= limit;
}

